import{_ as e,c as a,o as t,a4 as o}from"./chunks/framework.nQaBHiNx.js";const f=JSON.parse('{"title":"代码整洁之道","description":"","frontmatter":{},"headers":[],"relativePath":"computer/book/the-art-of-clean-code/index.md","filePath":"computer/book/the-art-of-clean-code/index.md"}'),r={name:"computer/book/the-art-of-clean-code/index.md"},n=o('<h1 id="代码整洁之道" tabindex="-1">代码整洁之道 <a class="header-anchor" href="#代码整洁之道" aria-label="Permalink to &quot;代码整洁之道&quot;">​</a></h1><p>软件质量，不但依赖架构及项目管理，而且与代码质量紧密相关。这一点，无论是敏捷开发流派还是传统开发流派，都不得不承认。本书提出一种观点：代码质量与其整洁度成正比。干净的代码，既在质量上较为可靠，也为后期维护、升级奠定了良好基础。作为编程领域的佼佼者，本书作者给出了一系列行之有效的整洁代码操作实践。这些实践在本书中体现为一条条规则（或称“启示”），并辅以来自实际项目的正、反两面的范例。只要遵循这些规则，就能编写出干净的代码，从而有效提升代码质量。</p><p>本书阅读对象为一切有志于改善代码质量的程序员及技术经理。书中介绍的规则均来自作者多年的实践经验，涵盖从命名到重构的多个编程方面，虽为一“家”之言，然诚有可资借鉴的价值。</p><h2 id="作者简介" tabindex="-1">作者简介 <a class="header-anchor" href="#作者简介" aria-label="Permalink to &quot;作者简介&quot;">​</a></h2><p>Robert C. Martin，世界级软件开发大师，设计模式和敏捷开发先驱，敏捷联盟首任主席，C++ Report前主编，被后辈程序员尊称为“Bob大叔”。20世纪70年代初成为职业程序员，后创办Object Mentor公司并任总裁。Martin还是一名多产的作家，至今已发表数百篇文章、论文和博客文章。除本书外，还著有《代码整洁之道：程序员的职业素养》《敏捷软件开发：原则、模式和实践》《UML：Java程序员指南》等。</p><h2 id="学习资料" tabindex="-1">学习资料 <a class="header-anchor" href="#学习资料" aria-label="Permalink to &quot;学习资料&quot;">​</a></h2><p><a href="https://book.douban.com/subject/34986245/" target="_blank" rel="noreferrer">豆瓣读书 - 《代码整洁之道》</a></p>',7),c=[n];function i(d,s,_,h,l,p){return t(),a("div",null,c)}const m=e(r,[["render",i]]);export{f as __pageData,m as default};
